import requests
import json

# Define RabbitMQ management URL, username, password, and port
RABBITMQ_URL = 'http://localhost:15672'
USERNAME = 'guest'
PASSWORD = 'guest'

def create_vhost(vhost_name):
    """Create a new virtual host"""
    url = f'{RABBITMQ_URL}/api/vhosts'
    headers = {'Content-Type': 'application/json'}
    data = json.dumps({'name': vhost_name})
    response = requests.post(url, auth=(USERNAME, PASSWORD), headers=headers, data=data)
    if response.status_code == 201:
        print(f'Virtual host {vhost_name} created successfully')
    else:
        print(f'Failed to create virtual host {vhost_name}')

def grant_permissions(vhost_name, username, password):
    """Grant permissions for queue operations"""
    url = f'{RABBITMQ_URL}/api/permissions/{vhost_name}'
    headers = {'Content-Type': 'application/json'}
    data = json.dumps({'vhost': vhost_name, 'user': username, 'password': password, 'tags': ['^amq\.queue', '^amq\.exchange']})
    response = requests.put(url, auth=(USERNAME, PASSWORD), headers=headers, data=data)
    if response.status_code == 200:
        print(f'Permissions granted for user {username} in virtual host {vhost_name}')
    else:
        print(f'Failed to grant permissions for user {username} in virtual host {vhost_name}')

def create_user(vhost_name, username, password):
    """Create a new user"""
    url = f'{RABBITMQ_URL}/api/users'
    headers = {'Content-Type': 'application/json'}
    data = json.dumps({'name': username, 'password': password, 'tags': ['administrator']})
    response = requests.post(url, auth=(USERNAME, PASSWORD), headers=headers, data=data)
    if response.status_code == 201:
        print(f'User {username} created successfully')
    else:
        print(f'Failed to create user {username}')

# Create virtual hosts for different applications
vhosts = ['app1', 'app2', 'app3']
for vhost in vhosts:
    create_vhost(vhost)

# Grant permissions and create users for each application
users = {
    'app1': {'username': 'app1_user', 'password': 'password123'},
    'app2': {'username': 'app2_user', 'password': 'password456'},
    'app3': {'username': 'app3_user', 'password': 'password789'}
}

for vhost, user in users.items():
    grant_permissions(vhost, user['username'], user['password'])
    create_user(vhost, user['username'], user['password'])